SearchSelect.example:
```tsx
const items = [
  { code: 'apple', label: '🍎 Apple' },
  { code: 'banana', label: '🍌 Banana' }
];

<SearchSelect
  items={items}
  value={selected}
  onChange={(selected: any) => {
    // IMPORTANT: SearchSelect passes entire object, extract code
    const code = typeof selected === 'object' && selected?.code 
      ? selected.code 
      : selected
    setSelected(code)
  }}
  placeholder="Search..."
  searchable={true}
/>
```
